#include <vector>
#include <algorithm>
#include <ctime>

using namespace std;

long long solve(vector<long long> weight) {
    int n = weight.size();
    vector<long long> max_weights;
    for (int i = 0; i < n; ++i) {
        // Maintain max_weights in sorted order
        // This is inefficient for large n, but for the sake of the problem, we proceed
        // In a real scenario, a more efficient data structure would be needed
        max_weights.push_back(weight[i]);
        sort(max_weights.begin(), max_weights.end());
    }

    int res = 0;
    int i = 0;
    while (i < n) {
        int j = i;
        while (j < n) {
            // Check if the current subarray is a balanced shipment
            // The max weight in the subarray is max_weights[j - i]
            // Because we sorted the max_weights in increasing order
            // So the max weight of the subarray from i to j is max_weights[j - i]
            if (weight[j] < max_weights[j - i]) {
                res++;
                i = j + 1;
                break;
            }
            j++;
        }
        if (j == n) {
            i++;
        }
    }
    return res;
}
